3	// CatalogEntry defines a logical model ref or profile's surface mappings.
4	// DDx uses this to project a ref (alias, profile, or canonical name) onto
5	// harness-specific surfaces and to surface deprecation/replacement metadata.
6	type CatalogEntry struct {
7		// Ref is the logical name (e.g. "qwen3", "cheap", "fast", "smart").
8		Ref string
9		// Surfaces maps a harness surface identifier to the concrete model string
10		// to pass to that harness. A ref absent from a surface's map means that
11		// surface cannot serve the ref.
12		Surfaces map[string]string
13		// Deprecated marks this ref as deprecated.
14		Deprecated bool
15		// ReplacedBy is the canonical replacement ref when Deprecated is true.
16		ReplacedBy string
17		// Blocked marks this ref as blocked; Resolve() returns ok=false for blocked entries.
18		Blocked bool
19	}
20	
21	// DeprecatedPin records a deprecated explicit model version string.
22	// Use this for exact concrete model pins (e.g. "claude-opus-4-5") that are
23	// stale — as opposed to logical alias deprecations in CatalogEntry.
24	type DeprecatedPin struct {
25		// Pin is the deprecated exact model string (e.g. "claude-opus-4-5").
26		Pin string
27		// ReplacedBy is the canonical replacement: a catalog ref (e.g. "smart")
28		// or a newer exact model string (e.g. "claude-opus-4-6").
29		ReplacedBy string
30		// Surface constrains the deprecation to a specific harness surface.
31		// Empty means the pin is deprecated across all surfaces.
32		Surface string
33	}
