140	// Resolve returns the concrete model string for a ref on the given surface.
141	// Returns ("", false) if the ref is unknown, not mapped to this surface,
142	// the entry is blocked, or the resolved concrete model is blocked.
143	func (c *Catalog) Resolve(ref, surface string) (string, bool) {
144		e, ok := c.entries[ref]
145		if !ok {
146			return "", false
147		}
148		if e.Blocked {
149			return "", false
150		}
151		model, ok := e.Surfaces[surface]
152		if !ok {
153			return "", false
154		}
155		if c.blockedModelIDs[model] {
156			return "", false
157		}
158		return model, true
159	}
