198	func buildBuiltinCatalog() *Catalog {
199		yml := DefaultModelCatalogYAML()
200	
201		// Build tier entries from YAML seed.
202		var entries []CatalogEntry
203		for tierName, tierDef := range yml.Tiers {
204			entry := CatalogEntry{
205				Ref:      tierName,
206				Surfaces: make(map[string]string, len(tierDef.Surfaces)),
207			}
208			for surface, model := range tierDef.Surfaces {
209				entry.Surfaces[surface] = model
210			}
211			entries = append(entries, entry)
212		}
213	
214		// Policy aliases: logical names not tied to a tier profile.
215		entries = append(entries,
216			// qwen3 is only available via the embedded OpenAI-compatible surface.
217			CatalogEntry{
218				Ref:      "qwen3",
219				Surfaces: map[string]string{"embedded-openai": "qwen/qwen3-coder-next"},
220			},
221			// codex-mini is a deprecated alias for the cheap codex model.
222			CatalogEntry{
223				Ref:        "codex-mini",
224				Surfaces:   map[string]string{"codex": "gpt-5.4-mini"},
225				Deprecated: true,
226				ReplacedBy: "cheap",
227			},
228		)
229	
230		pins := []DeprecatedPin{
231			// Stale exact version strings for the claude (Anthropic) family.
232			{Pin: "claude-opus-4-5", Surface: "claude", ReplacedBy: "claude-opus-4-6"},
233			{Pin: "claude-3-5-sonnet-20241022", Surface: "claude", ReplacedBy: "claude-sonnet-4-6"},
234			{Pin: "claude-3-opus-20240229", Surface: "claude", ReplacedBy: "claude-opus-4-6"},
235			{Pin: "claude-3-sonnet-20240229", Surface: "claude", ReplacedBy: "claude-sonnet-4-6"},
236			// Stale exact version strings for the codex (OpenAI) family.
237			{Pin: "gpt-4o", Surface: "codex", ReplacedBy: "gpt-5.4-mini"},
238			{Pin: "gpt-4-turbo", Surface: "codex", ReplacedBy: "gpt-5.4"},
239			{Pin: "o1-2024-12-17", Surface: "codex", ReplacedBy: "gpt-5.4"},
240		}
241	
242		return NewCatalogWithPins(entries, pins)
243	}
