18	// ApplyCatalogFromService overlays agentlib profile data onto a DDx Catalog.
19	// It enumerates profiles via svc.ListProfiles and resolves surface-specific
20	// models via svc.ResolveProfile. Individual profile errors are silently skipped;
21	// the builtin catalog remains the fallback for any unresolvable entry.
22	func ApplyCatalogFromService(ctx context.Context, cat *Catalog, svc agentlib.DdxAgent) {
23		if cat == nil || svc == nil {
24			return
25		}
26		profiles, err := svc.ListProfiles(ctx)
27		if err != nil || len(profiles) == 0 {
28			return
29		}
30		for _, p := range profiles {
31			resolved, err := svc.ResolveProfile(ctx, p.Name)
32			if err != nil || resolved == nil {
33				if p.Deprecated {
34					cat.AddOrReplace(CatalogEntry{
35						Ref:        p.Name,
36						Deprecated: true,
37						ReplacedBy: p.Replacement,
38					})
39				}
40				continue
41			}
42			surfaces := make(map[string]string, len(resolved.Surfaces))
43			for _, s := range resolved.Surfaces {
44				dst, ok := profileSurfaceToDDx[s.Name]
45				if !ok || s.Model == "" {
46					continue
47				}
48				surfaces[dst] = s.Model
49			}
50			if len(surfaces) == 0 && !resolved.Deprecated {
51				continue
52			}
53			cat.AddOrReplace(CatalogEntry{
54				Ref:        p.Name,
55				Surfaces:   surfaces,
56				Deprecated: resolved.Deprecated,
57				ReplacedBy: resolved.Replacement,
58			})
59		}
60	}
